import java.util.Base64;
import java.util.List;
import java.util.ArrayList;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

public class MultipartContentProcessor {

    public String processContent(String multipartContent) {
        if (multipartContent == null || multipartContent.isEmpty()) {
            throw new IllegalArgumentException("Input content cannot be null or empty");
        }

        List<String> parts = extractParts(multipartContent);
        StringBuilder combinedContent = new StringBuilder();

        for (String part : parts) {
            if (isHtmlPart(part)) {
                combinedContent.append(part);
            } else if (isImagePart(part)) {
                String base64Image = extractBase64Image(part);
                if (base64Image != null) {
                    combinedContent.append("<img src='data:image/png;base64,").append(base64Image).append("'/>");
                }
            }
        }

        return combinedContent.toString();
    }

    private List<String> extractParts(String multipartContent) {
        List<String> parts = new ArrayList<>();
        String[] splitParts = multipartContent.split("--boundary"); // Assuming a boundary is defined
        for (String part : splitParts) {
            if (!part.trim().isEmpty()) {
                parts.add(part.trim());
            }
        }
        return parts;
    }

    private boolean isHtmlPart(String part) {
        return part.startsWith("Content-Type: text/html");
    }

    private boolean isImagePart(String part) {
        return part.startsWith("Content-Type: image/png") || part.startsWith("Content-Type: image/jpeg");
    }

    private String extractBase64Image(String part) {
        Pattern pattern = Pattern.compile("base64,(.+)");
        Matcher matcher = pattern.matcher(part);
        if (matcher.find()) {
            return matcher.group(1);
        }
        return null;
    }
}
